INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'What is the central economic problem?', 'Scarcity: human wants are unlimited but the resources (factors of production) available to satisfy them are finite, so choices must be made about what to produce, how, and for whom.', 1, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'List the four factors of production with their respective rewards.', 'Land (rent), labour (wages), capital (interest), enterprise (profit). Enterprise organises the other three and bears risk.', 2, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'Define opportunity cost.', 'The value of the next-best alternative forgone when a choice is made. It applies to consumers, firms and governments.', 3, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'What does a Production Possibility Frontier (PPF) show?', 'The maximum combinations of two goods an economy can produce when all resources are fully and efficiently employed, given the current state of technology. <svg viewBox="0 0 220 150" width="220" height="150" style="display:block;margin:6px auto"><line x1="30" y1="130" x2="205" y2="130" stroke="#0B1E3F"/><line x1="30" y1="130" x2="30" y2="20" stroke="#0B1E3F"/><path d="M30 25 Q70 32 130 75 T200 130" stroke="#0B1E3F" stroke-width="1.5" fill="none"/><text x="205" y="145" font-size="9" fill="#0B1E3F" text-anchor="end">Good X</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">Good Y</text><text x="135" y="105" font-size="9" fill="#0B1E3F">PPF</text></svg>', 4, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'What does a point inside the PPF indicate?', 'Productive inefficiency or unemployed/underused resources — output could be increased without sacrificing any other good.', 5, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'Why is a PPF typically concave to the origin?', 'Because resources are not equally productive in all uses; reallocating them yields increasing opportunity costs as factors better suited to the other good must eventually be transferred.', 6, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'Distinguish economic growth from economic development.', 'Growth = rise in real GDP (quantitative). Development = broader improvement in living standards including health, education, equality and political freedom (qualitative).', 7, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'Distinguish positive and normative statements.', 'Positive statements describe what is and can be tested against evidence. Normative statements involve value judgements about what ought to be and cannot be empirically verified.', 8, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'What is the difference between a free market, command and mixed economy?', 'Free market: resources allocated by price signals and private ownership. Command: state plans and owns resources. Mixed: combines private market with public-sector provision and regulation — most real economies.',9, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'State Adam Smith''s ''invisible hand'' idea.', 'Self-interested individuals trading in competitive markets are guided as if by an invisible hand to allocate resources efficiently and benefit society.', 10, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'Define specialisation and the division of labour.', 'Specialisation: workers/firms/countries focus on the tasks they are best at. Division of labour: breaking production into specialised tasks performed by different workers, raising productivity (Smith''s pin factory).', 11, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'Give two advantages and one disadvantage of the division of labour.', 'Advantages: higher productivity from practice; lower training costs per task; faster output. Disadvantage: monotony lowers worker morale, raising turnover and absenteeism.', 12, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'What three functions does money perform?', 'Medium of exchange (replaces barter), store of value (purchasing power preserved over time), unit of account (common measure of value). Some texts add ''standard of deferred payment''.', 13, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'Why does an outward shift of the PPF represent economic growth?', 'It signals that potential output has risen — through more or better factors of production (investment, education, immigration) or improved technology — so previously unattainable combinations are now feasible.', 14, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'What is the ceteris paribus assumption?', 'Latin for ''other things equal'' — economists isolate the effect of one variable by holding all others constant, an essential simplifying assumption when building models.', 15, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'The Economic Problem and Methodology', 'Why are economic models simplifications?', 'Because the real economy contains millions of agents and variables; models abstract from detail to identify causal relationships and make predictions, accepting some loss of realism.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'State the law of demand.', 'Ceteris paribus, as price falls, quantity demanded rises (and vice versa). Demand curves slope downwards because of the income effect, the substitution effect and diminishing marginal utility.', 1, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'Distinguish a movement along a demand curve from a shift of it.', 'A movement (extension/contraction) is caused by a change in the good''s own price. A shift is caused by a change in any other determinant (income, related-good prices, tastes, expectations, population).', 2, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'What is consumer surplus?', 'The difference between the maximum price consumers are willing to pay and the price they actually pay — represented by the area below the demand curve and above the market price up to the equilibrium quantity.', 3, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'Define price elasticity of demand (PED) and give its formula.', 'PED measures the responsiveness of quantity demanded to a change in price. PED = % change in Qd / % change in P. It is normally negative; sign is conventionally ignored.', 4, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'Name three determinants of PED.', 'Availability and closeness of substitutes; share of income spent on the good; necessity vs luxury; time period (more elastic in the long run); habit/addiction.', 5, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'Relate PED to total revenue.', 'If demand is price-elastic (|PED| > 1), a price cut raises total revenue. If inelastic (|PED| < 1), a price cut lowers total revenue. At unitary elasticity, revenue is maximised.', 6, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'Define cross elasticity of demand (XED).', 'XED = % change in Qd of good A / % change in P of good B. Positive XED indicates substitutes (e.g. Coke and Pepsi); negative XED indicates complements (e.g. cars and petrol).', 7, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'Define income elasticity of demand (YED) and interpret its sign.', 'YED = % change in Qd / % change in income. Positive: normal good (luxury if YED>1, necessity if 0<YED<1). Negative: inferior good — demand falls as income rises.', 8, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'State the law of supply.', 'Ceteris paribus, as price rises, quantity supplied rises. Supply curves slope upwards because higher prices cover higher marginal costs and incentivise producers to expand output.', 9, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'Name three determinants that shift the supply curve.', 'Costs of production (wages, raw materials), technology, indirect taxes/subsidies, the number of firms, expectations and producer goals. A change in own price moves along the curve, not shifts it.', 10, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'Define price elasticity of supply (PES).', 'PES = % change in Qs / % change in P. PES depends on spare capacity, ease of stockholding, factor mobility and the time horizon — supply is more elastic in the long run.', 11, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'How is market equilibrium determined?', 'Where the demand and supply curves intersect — quantity demanded equals quantity supplied at the market-clearing price. Surplus pushes price down; shortage pushes it up. <svg viewBox="0 0 220 150" width="220" height="150" style="display:block;margin:6px auto"><line x1="30" y1="130" x2="205" y2="130" stroke="#0B1E3F"/><line x1="30" y1="130" x2="30" y2="20" stroke="#0B1E3F"/><line x1="45" y1="30" x2="195" y2="125" stroke="#0B1E3F" stroke-width="1.5"/><line x1="45" y1="125" x2="195" y2="30" stroke="#0B1E3F" stroke-width="1.5"/><line x1="30" y1="78" x2="120" y2="78" stroke="#0B1E3F" stroke-width="0.5" stroke-dasharray="2 2"/><line x1="120" y1="78" x2="120" y2="130" stroke="#0B1E3F" stroke-width="0.5" stroke-dasharray="2 2"/><text x="198" y="125" font-size="9" fill="#0B1E3F">D</text><text x="198" y="30" font-size="9" fill="#0B1E3F">S</text><text x="28" y="81" font-size="9" fill="#0B1E3F" text-anchor="end">P*</text><text x="120" y="145" font-size="9" fill="#0B1E3F" text-anchor="middle">Q*</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">P</text><text x="205" y="145" font-size="9" fill="#0B1E3F" text-anchor="end">Q</text></svg>', 12, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'What does the price mechanism do? (Three functions)', 'Signalling (prices convey information about scarcity), incentive (high prices attract producers and ration consumers) and rationing (price rises so demand equals supply when goods are scarce).', 13, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'What does producer surplus represent?', 'The difference between the price producers receive and the minimum they would be willing to accept — the area above the supply curve and below the market price.', 14, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'Explain joint demand and competitive demand with examples.', 'Joint (complements): goods bought together — printers and ink. Competitive (substitutes): goods bought as alternatives — butter and margarine. Joint supply: producing one good automatically yields another (beef and leather).', 15, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination in a Competitive Market', 'How does a sales tax (specific tax) affect equilibrium when demand is inelastic?', 'It shifts supply leftward by the tax. With inelastic demand, the consumer bears most of the burden (incidence) — price rises sharply, quantity falls a little, and tax revenue is large.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'Distinguish production from productivity.', 'Production = total quantity of output produced. Productivity = output per unit of input (labour productivity = output per worker per hour). Productivity drives long-run living standards.', 1, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'State the law of diminishing marginal returns.', 'In the short run, as more variable input is added to a fixed input, the marginal product of the variable input eventually falls. It causes the short-run MC curve to slope upward.', 2, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'Distinguish fixed and variable costs.', 'Fixed costs do not vary with output (rent, insurance, salaried staff). Variable costs change with output (raw materials, wages of hourly workers). FC + VC = TC.', 3, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'Define average cost and marginal cost.', 'AC = TC/Q (cost per unit). MC = ΔTC/ΔQ (cost of producing one more unit). MC cuts AC at its minimum because adding a unit cheaper than average pulls average down.', 4, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'Why is the short-run AC curve U-shaped?', 'Initially, spreading fixed costs over more units lowers AFC and AC; eventually diminishing returns raise AVC and pull AC back up. The minimum is the productively efficient level of output. <svg viewBox="0 0 220 150" width="220" height="150" style="display:block;margin:6px auto"><line x1="30" y1="130" x2="205" y2="130" stroke="#0B1E3F"/><line x1="30" y1="130" x2="30" y2="20" stroke="#0B1E3F"/><path d="M40 50 Q90 110 130 80 T200 35" stroke="#0B1E3F" stroke-width="1.5" fill="none"/><path d="M40 90 Q100 120 140 95 T200 50" stroke="#0B1E3F" stroke-width="1.5" fill="none" stroke-dasharray="3 2"/><circle cx="125" cy="92" r="2.5" fill="#0B1E3F"/><text x="198" y="35" font-size="9" fill="#0B1E3F">MC</text><text x="198" y="55" font-size="9" fill="#0B1E3F">AC</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">£</text><text x="205" y="145" font-size="9" fill="#0B1E3F" text-anchor="end">Q</text></svg>', 5, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'Define returns to scale.', 'Long-run response of output to a proportional change in all inputs. Increasing returns: output rises more than proportionally. Constant: same proportion. Decreasing: less than proportional.', 6, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'List four internal economies of scale.', 'Technical (specialised capital), purchasing (bulk-buy discounts), managerial (specialist managers), financial (cheaper borrowing), marketing, risk-bearing. They lower long-run AC as the firm grows.', 7, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'What are diseconomies of scale?', 'The rise in long-run AC as a firm grows past its minimum efficient scale, due to coordination problems, communication breakdown, motivational issues and ''X-inefficiency'' from weak supervision.', 8, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'Distinguish internal and external economies of scale.', 'Internal: arise within the firm as it grows. External: arise within the industry as a whole (skilled labour pool, specialist suppliers, infrastructure clustering — e.g. Silicon Valley).', 9, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'Define total, average and marginal revenue.', 'TR = P × Q. AR = TR/Q = price (same as the demand curve). MR = ΔTR/ΔQ. For a price taker AR = MR; for a price maker MR < AR and slopes more steeply.', 10, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'State the profit-maximisation rule.', 'Produce where MC = MR (and MC is rising). At this output, the gap between TR and TC is largest.', 11, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'Distinguish normal and supernormal (abnormal) profit.', 'Normal profit: minimum return needed to keep resources in their current use; counted as a cost in economics. Supernormal profit: any profit above normal — attracts new entrants in competitive markets.', 12, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'State the short-run shut-down rule.', 'A firm continues operating in the short run as long as price ≥ AVC, since it can still cover variable costs and contribute to fixed costs. If P < AVC, shut down to limit losses to fixed costs.', 13, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'Distinguish productive and allocative efficiency.', 'Productive efficiency: producing at minimum AC (no waste of resources). Allocative efficiency: producing the goods consumers value most, where P = MC, maximising society''s welfare.', 14, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'What is X-inefficiency?', 'A failure to minimise costs because firms lack competitive pressure — managerial slack, generous perks, bloated workforces. Common in monopolies and state monopolies.', 15, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production, Costs and Revenue', 'Why might a firm have other objectives than profit-maximisation?', 'Imperfect information, principal-agent problems (managers maximise their own utility), satisficing (Simon), revenue or sales maximisation (Baumol), market-share targets, social/ethical aims.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'List the four assumptions of perfect competition.', 'Many small buyers and sellers (price takers); identical (homogeneous) products; perfect information; free entry and exit (no barriers).', 1, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'Why does a perfectly competitive firm face a horizontal demand curve?', 'Because it is a price taker — its output is too small to influence the market price. AR = MR = market price; any attempt to charge more loses all customers.', 2, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'What happens to supernormal profits in perfect competition in the long run?', 'New firms are attracted by the profit, supply rises, market price falls until each remaining firm earns only normal profit. The long-run equilibrium has P = AC = MC = MR.', 3, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'Why is perfect competition both productively and allocatively efficient in the long run?', 'P = minimum AC (productive efficiency) and P = MC (allocative efficiency). Consumers get goods at the lowest possible cost equal to their valuation.', 4, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'Define monopolistic competition and give an example.', 'Many firms selling slightly differentiated products with low entry barriers — e.g. hairdressers, restaurants. Each has a downward-sloping demand curve from product differentiation but earns only normal profit long run.', 5, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'List four characteristics of an oligopoly.', 'Few large firms dominate, high concentration ratio, interdependent decisions, significant barriers to entry, products differentiated or homogeneous, non-price competition important.', 6, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'What is the n-firm concentration ratio?', 'The combined market share of the largest n firms. CR4 above ~50% suggests an oligopolistic structure. UK supermarkets have a high CR4.', 7, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'Explain the kinked demand curve.', 'In oligopoly, rivals match price cuts (so demand is inelastic below the kink) but ignore price rises (so demand is elastic above). MR has a vertical gap — explains observed price stability despite cost changes. <svg viewBox="0 0 220 150" width="220" height="150" style="display:block;margin:6px auto"><line x1="30" y1="130" x2="205" y2="130" stroke="#0B1E3F"/><line x1="30" y1="130" x2="30" y2="20" stroke="#0B1E3F"/><line x1="45" y1="35" x2="115" y2="75" stroke="#0B1E3F" stroke-width="1.5"/><line x1="115" y1="75" x2="195" y2="125" stroke="#0B1E3F" stroke-width="1.5"/><line x1="45" y1="55" x2="115" y2="95" stroke="#0B1E3F" stroke-width="1" stroke-dasharray="3 2"/><line x1="115" y1="115" x2="170" y2="125" stroke="#0B1E3F" stroke-width="1" stroke-dasharray="3 2"/><line x1="115" y1="95" x2="115" y2="115" stroke="#0B1E3F" stroke-width="1" stroke-dasharray="3 2"/><circle cx="115" cy="75" r="2.5" fill="#0B1E3F"/><text x="115" y="68" font-size="8" fill="#0B1E3F" text-anchor="middle">kink</text><text x="198" y="125" font-size="9" fill="#0B1E3F">D</text><text x="170" y="135" font-size="9" fill="#0B1E3F">MR</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">P</text><text x="205" y="145" font-size="9" fill="#0B1E3F" text-anchor="end">Q</text></svg>', 8, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'Distinguish collusive and non-collusive oligopoly.', 'Collusive: firms cooperate to fix prices/output (cartel) — illegal in UK/EU. Non-collusive: firms compete independently, often using price wars or non-price competition.', 9, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'What does the prisoners'' dilemma reveal about cartels?', 'Each firm has an individual incentive to cheat by cutting price below the agreed level, even though all are worse off if they all cheat. Explains why cartels are unstable without strong enforcement.', 10, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'List three forms of non-price competition.', 'Advertising and branding, product differentiation/quality, after-sales service, loyalty schemes, packaging, location. Used to gain market share without triggering price wars.', 11, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'Define a pure monopoly and a working monopoly.', 'Pure: a single firm is the only seller. Working/legal: a firm with ≥ 25% market share (UK definition under the Competition Act 1998), having significant market power.', 12, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'How does a profit-maximising monopolist set price and output?', 'Output where MC = MR; price read off the demand (AR) curve at that quantity. Result: higher P, lower Q than under perfect competition, with supernormal profit sustained by entry barriers. <svg viewBox="0 0 240 160" width="240" height="160" style="display:block;margin:6px auto"><line x1="30" y1="135" x2="225" y2="135" stroke="#0B1E3F"/><line x1="30" y1="135" x2="30" y2="20" stroke="#0B1E3F"/><line x1="40" y1="35" x2="195" y2="130" stroke="#0B1E3F" stroke-width="1.5"/><line x1="40" y1="35" x2="120" y2="130" stroke="#0B1E3F" stroke-width="1.5"/><path d="M40 90 Q90 130 130 95 T200 60" stroke="#0B1E3F" stroke-width="1.5" fill="none"/><path d="M40 110 Q100 130 140 105 T210 75" stroke="#0B1E3F" stroke-width="1" fill="none" stroke-dasharray="3 2"/><line x1="30" y1="60" x2="100" y2="60" stroke="#0B1E3F" stroke-width="0.5" stroke-dasharray="2 2"/><line x1="30" y1="92" x2="100" y2="92" stroke="#0B1E3F" stroke-width="0.5" stroke-dasharray="2 2"/><line x1="100" y1="60" x2="100" y2="135" stroke="#0B1E3F" stroke-width="0.5" stroke-dasharray="2 2"/><rect x="30" y="60" width="70" height="32" fill="#0B1E3F" fill-opacity="0.12"/><text x="198" y="130" font-size="9" fill="#0B1E3F">D=AR</text><text x="123" y="135" font-size="9" fill="#0B1E3F">MR</text><text x="200" y="62" font-size="9" fill="#0B1E3F">MC</text><text x="210" y="78" font-size="9" fill="#0B1E3F">AC</text><text x="28" y="63" font-size="9" fill="#0B1E3F" text-anchor="end">Pm</text><text x="100" y="148" font-size="9" fill="#0B1E3F" text-anchor="middle">Qm</text><text x="60" y="80" font-size="8" fill="#0B1E3F">profit</text></svg>', 13, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'Give two costs and two benefits of monopoly.', 'Costs: higher prices, lower output, allocative inefficiency, X-inefficiency. Benefits: economies of scale (lower AC), supernormal profits fund R&D and dynamic efficiency, may be a natural monopoly.', 14, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'Define a natural monopoly.', 'An industry where long-run AC keeps falling over the entire range of market demand — one firm can supply the market more cheaply than several. Examples: water, electricity grid, rail networks. <svg viewBox="0 0 220 150" width="220" height="150" style="display:block;margin:6px auto"><line x1="30" y1="130" x2="205" y2="130" stroke="#0B1E3F"/><line x1="30" y1="130" x2="30" y2="20" stroke="#0B1E3F"/><path d="M40 35 C90 90 140 110 200 120" stroke="#0B1E3F" stroke-width="1.5" fill="none"/><line x1="40" y1="40" x2="200" y2="125" stroke="#0B1E3F" stroke-width="1.5"/><text x="200" y="35" font-size="9" fill="#0B1E3F" text-anchor="end">LRAC</text><text x="200" y="138" font-size="9" fill="#0B1E3F" text-anchor="end">D</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">£</text><text x="205" y="145" font-size="9" fill="#0B1E3F" text-anchor="end">Q</text></svg>', 15, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive and Concentrated Markets', 'What three conditions are needed for price discrimination?', 'Market power (firm is a price maker), ability to identify groups with different PEDs, and ability to prevent resale (no arbitrage). Examples: peak/off-peak rail fares, student/adult cinema tickets.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'Define market failure.', 'When the free market fails to allocate resources efficiently, leading to a loss of social welfare. Includes externalities, public goods, information failure, monopoly power and inequality.', 1, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'Distinguish private, external and social cost.', 'Private cost: borne by the producer/consumer. External cost: spillover onto third parties (pollution). Social cost = private + external. The free market ignores external costs, leading to overproduction.', 2, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'How do you identify a negative production externality on a diagram?', 'MSC lies above MPC. The free-market output (where MPB = MPC) exceeds the socially optimum output (where MSB = MSC), creating a deadweight welfare loss triangle. <svg viewBox="0 0 240 150" width="240" height="150" style="display:block;margin:6px auto"><line x1="30" y1="130" x2="225" y2="130" stroke="#0B1E3F"/><line x1="30" y1="130" x2="30" y2="20" stroke="#0B1E3F"/><line x1="45" y1="30" x2="200" y2="125" stroke="#0B1E3F" stroke-width="1.5"/><line x1="45" y1="125" x2="200" y2="30" stroke="#0B1E3F" stroke-width="1.5"/><line x1="65" y1="125" x2="220" y2="22" stroke="#0B1E3F" stroke-width="1.5" stroke-dasharray="3 2"/><polygon points="115,75 145,55 145,90" fill="#B00020" fill-opacity="0.3"/><text x="203" y="125" font-size="9" fill="#0B1E3F">D=MPB</text><text x="203" y="30" font-size="9" fill="#0B1E3F">MPC</text><text x="223" y="20" font-size="9" fill="#0B1E3F" text-anchor="end">MSC</text><text x="118" y="80" font-size="8" fill="#B00020">DWL</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">P</text><text x="225" y="145" font-size="9" fill="#0B1E3F" text-anchor="end">Q</text></svg>', 3, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'What are merit and demerit goods?', 'Merit goods: undervalued by consumers, underconsumed (education, healthcare). Demerit goods: overvalued, overconsumed (cigarettes, alcohol). Reflect information failure and positive/negative externalities.', 4, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'State the two characteristics of a public good.', 'Non-rival (one person''s use does not reduce another''s) and non-excludable (no one can be prevented from using it). Examples: street lighting, national defence. Free-rider problem leads to under-provision.', 5, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'What is the free-rider problem?', 'Because public goods are non-excludable, individuals can benefit without paying. Profit-maximising firms cannot recoup costs, so the good is under-provided by the market — justifying state provision.', 6, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'How does asymmetric information cause market failure?', 'When one party in a transaction has more information than the other, leading to adverse selection (used-car market — Akerlof''s lemons) and moral hazard (insured drivers take more risks).', 7, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'Evaluate an indirect tax to correct a negative externality.', 'Strengths: internalises external cost (Pigouvian), generates revenue to compensate victims, signals harm. Weaknesses: hard to set at exactly MEC, regressive, may push activity into black markets, inelastic demand limits effect on quantity.', 8, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'How does a tradeable pollution permit (cap-and-trade) work?', 'Government caps total emissions and issues permits. Firms that pollute below their allowance sell surplus permits; heavy polluters must buy. Market price of permits reflects MEC; cap can be tightened over time. Used by EU ETS.', 9, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'What is a subsidy and a likely diagrammatic effect?', 'A government grant that reduces production cost or consumption price. It shifts supply rightward (or demand rightward if to consumers), raising output to the socially optimum level for goods with positive externalities.', 10, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'Compare maximum and minimum prices.', 'Maximum (price ceiling) below equilibrium creates a shortage and possible black market (e.g. rent controls). Minimum (price floor) above equilibrium creates a surplus and may need government to buy excess (e.g. minimum wage, EU CAP). <svg viewBox="0 0 220 150" width="220" height="150" style="display:block;margin:6px auto"><line x1="30" y1="130" x2="205" y2="130" stroke="#0B1E3F"/><line x1="30" y1="130" x2="30" y2="20" stroke="#0B1E3F"/><line x1="45" y1="30" x2="195" y2="125" stroke="#0B1E3F" stroke-width="1.5"/><line x1="45" y1="125" x2="195" y2="30" stroke="#0B1E3F" stroke-width="1.5"/><line x1="30" y1="50" x2="205" y2="50" stroke="#B00020" stroke-width="1.2"/><line x1="30" y1="105" x2="205" y2="105" stroke="#B00020" stroke-width="1.2" stroke-dasharray="4 2"/><text x="208" y="52" font-size="9" fill="#B00020">P min (floor)</text><text x="208" y="107" font-size="9" fill="#B00020">P max (ceiling)</text><text x="198" y="125" font-size="9" fill="#0B1E3F">D</text><text x="198" y="30" font-size="9" fill="#0B1E3F">S</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">P</text><text x="205" y="145" font-size="9" fill="#0B1E3F" text-anchor="end">Q</text></svg>', 11, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'Why might competition policy be needed?', 'To prevent abuse of monopoly power — anti-competitive mergers, predatory pricing, price-fixing cartels — and protect consumers from high prices and low choice. Enforced by the CMA in the UK.', 12, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'Distinguish privatisation, deregulation and nationalisation.', 'Privatisation: transfer of state assets to private sector. Deregulation: removal of restrictive rules to allow competition. Nationalisation: transfer of private firms into state ownership.', 13, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'What is regulatory capture?', 'When the regulator comes to act in the interests of the industry it regulates rather than consumers, due to lobbying, revolving doors of personnel, or asymmetric information.', 14, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'Define government failure.', 'When intervention to correct market failure produces a worse allocation of resources — caused by information gaps, unintended consequences, administrative costs, lobbying and short-termism.', 15, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure and Government Intervention', 'Give an example of unintended consequences of government intervention.', 'Rent controls reducing housing supply and quality; cigarette taxes funding smuggling; subsidies for biofuels raising food prices; minimum alcohol pricing reducing problem drinking but hitting low-income moderate drinkers.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'List the four main macroeconomic objectives.', 'Sustainable economic growth, low and stable inflation (~2% CPI), low unemployment (full employment), satisfactory balance of payments on current account. Often add: budget balance, fairer income distribution, environmental sustainability.', 1, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Distinguish nominal and real GDP.', 'Nominal GDP = output valued at current prices. Real GDP = output valued at constant (base-year) prices. Real GDP strips out inflation, so changes in real GDP reflect actual changes in output.', 2, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Why use GDP per capita instead of total GDP?', 'Total GDP rises with population. Dividing by population reflects average income/output per person — a better proxy for living standards across countries of different size.', 3, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Give three limitations of GDP as a measure of welfare.', 'Ignores income distribution; excludes the informal/black economy and household production; ignores environmental damage; says nothing about leisure, health or political freedom.', 4, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'What is the Human Development Index?', 'A UN composite index combining life expectancy, mean/expected years of schooling and GNI per capita (PPP) into a 0-1 score. Captures more dimensions of welfare than GDP alone.', 5, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'How is CPI calculated?', 'A weighted average of the prices of a representative basket of goods and services consumed by a typical household, weights based on Living Costs and Food Survey. Updated annually.', 6, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Distinguish CPI from RPI.', 'CPI excludes most housing costs and uses a geometric mean (substitution effect) — generally lower. RPI includes mortgage interest and council tax and uses arithmetic mean. Bank of England targets CPI.', 7, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'List three limitations of CPI.', 'Slow to capture quality changes; excludes ~10% of population (very low/high income); basket is updated annually but tastes can change quickly; does not reflect every household''s spending pattern.', 8, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'How is unemployment measured (UK)?', 'Two main methods: claimant count (those receiving JSA/Universal Credit) — narrow and quick; ILO/Labour Force Survey (anyone willing and able to work who hasn''t worked in the last week) — internationally comparable, broader.', 9, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Define the activity (participation) rate.', 'The economically active population (employed + unemployed) as a percentage of the working-age population. Rises if more women, students or older people enter the labour force.', 10, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'What does the balance of payments record?', 'All economic transactions between residents of the UK and the rest of the world over a period. Made up of the current account, capital account and financial account; sum should equal zero (with errors and omissions).', 11, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'List the four parts of the current account.', 'Trade in goods, trade in services, primary income (wages/investment income from abroad), secondary income (transfers — remittances, EU/UN payments, foreign aid).', 12, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'What does an index number tell you?', 'It re-bases a series so that the value in a chosen base year equals 100. Other values express the percentage change relative to that base, simplifying comparison over time.', 13, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'What is the difference between GDP and GNI?', 'GDP measures output produced within a country''s borders. GNI measures income earned by that country''s residents wherever produced. GNI = GDP + net primary income from abroad.', 14, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Define purchasing power parity (PPP).', 'An exchange rate that equalises the cost of a basket of goods in two countries. Using PPP rather than market rates makes cross-country GDP comparisons more meaningful — The Economist''s Big Mac Index is a popular illustration.', 15, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Distinguish absolute from relative poverty.', 'Absolute: income too low to afford basic essentials (World Bank: $2.15 a day, 2017 PPP). Relative: income below a threshold (commonly 60% of median income in the UK) — measures inequality more than survival.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Write the AD equation.', 'AD = C + I + G + (X − M). Consumption + investment + government spending + net exports.', 1, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Why does AD slope downwards?', 'Real-balance effect (lower price level raises real wealth and consumption); interest-rate effect (lower P -> lower money demand -> lower r -> more I); international trade effect (lower P makes exports more competitive).', 2, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Name three determinants of consumption.', 'Disposable income, interest rates, wealth (housing/financial), consumer confidence, expectations, availability of credit, taxation. The marginal propensity to consume falls as income rises.', 3, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Distinguish gross and net investment.', 'Gross investment = total spending on new capital goods. Net investment = gross investment minus capital depreciation (replacement). Net investment expands the capital stock and productive capacity.', 4, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Give three determinants of investment.', 'Expected returns/animal spirits, interest rates, business confidence, taxation/allowances, technology, retained profits, the accelerator effect (changes in demand drive investment).', 5, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'List four causes of an increase in AD.', 'Cuts in income tax, lower interest rates, weaker pound (boosts X, raises M cost), rising house prices, rising consumer/business confidence, higher government spending, faster world growth.', 6, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Distinguish SRAS and LRAS.', 'SRAS: upward-sloping; in the short run, higher P with sticky wages raises profit and output. LRAS: vertical at full-employment output (Yfe) on the classical view, or upward-sloping/curved on the Keynesian view (spare capacity).', 7, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'List three factors that shift LRAS.', 'Quantity/quality of labour (immigration, education), capital stock and investment, technology and productivity, enterprise/incentives, government supply-side policy (deregulation, infrastructure).', 8, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Compare classical and Keynesian LRAS curves.', 'Classical: vertical at Yfe — output cannot exceed potential, so AD changes only affect P. Keynesian: horizontal at low output, upward-sloping with spare capacity, vertical near Yfe — AD matters at low output. <svg viewBox="0 0 460 160" width="460" height="160" style="display:block;margin:6px auto"><g><line x1="30" y1="135" x2="200" y2="135" stroke="#0B1E3F"/><line x1="30" y1="135" x2="30" y2="20" stroke="#0B1E3F"/><line x1="140" y1="135" x2="140" y2="25" stroke="#0B1E3F" stroke-width="1.5"/><line x1="40" y1="30" x2="180" y2="125" stroke="#0B1E3F" stroke-width="1.5"/><text x="200" y="148" font-size="9" fill="#0B1E3F" text-anchor="end">Y</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">P</text><text x="143" y="20" font-size="9" fill="#0B1E3F">LRAS</text><text x="183" y="125" font-size="9" fill="#0B1E3F">AD</text><text x="115" y="155" font-size="9" fill="#0B1E3F" text-anchor="middle">Classical</text></g><g><line x1="260" y1="135" x2="440" y2="135" stroke="#0B1E3F"/><line x1="260" y1="135" x2="260" y2="20" stroke="#0B1E3F"/><path d="M260 110 L320 110 Q360 100 380 60 L380 25" stroke="#0B1E3F" stroke-width="1.5" fill="none"/><line x1="270" y1="35" x2="420" y2="125" stroke="#0B1E3F" stroke-width="1.5"/><text x="440" y="148" font-size="9" fill="#0B1E3F" text-anchor="end">Y</text><text x="258" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">P</text><text x="383" y="22" font-size="9" fill="#0B1E3F">LRAS</text><text x="423" y="125" font-size="9" fill="#0B1E3F">AD</text><text x="350" y="155" font-size="9" fill="#0B1E3F" text-anchor="middle">Keynesian</text></g></svg>', 9, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Define the multiplier and give the formula.', 'The ratio of final change in real GDP to the initial change in injections. k = 1/(1 − MPC) = 1/MPS in a closed economy with no government; in an open economy k = 1/(MPS + MPT + MPM).', 10, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'What determines the size of the multiplier?', 'The marginal propensities to consume (raises k) and to withdraw — save, tax, import (lowers k). Also depends on spare capacity: with little spare capacity, extra spending mostly raises prices.', 11, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'List the injections and withdrawals in the circular flow.', 'Injections: investment (I), government spending (G), exports (X). Withdrawals: saving (S), taxation (T), imports (M). Equilibrium: I + G + X = S + T + M.', 12, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'What is the accelerator effect?', 'The relationship by which a change in the rate of growth of output causes a much larger proportional change in investment, since firms only invest when expected demand growth justifies new capacity.', 13, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'How does an outward shift of AD affect P and Y on a Keynesian AS curve?', 'On the horizontal section: Y rises with P unchanged. On the upward-sloping section: P and Y both rise. On the vertical section: P rises with Y unchanged (pure inflation).', 14, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Why is consumer confidence important to AD?', 'Confidence shapes household saving and borrowing decisions, especially for big-ticket items. Falling confidence raises saving (precautionary motive) and lowers C, contracting AD.', 15, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'What is Say''s Law and which school accepts it?', 'Say''s Law: ''supply creates its own demand'' — production generates incomes that are spent on output. Accepted by classical economists, rejected by Keynes who argued saving may exceed investment.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Distinguish actual and trend (potential) growth.', 'Actual growth = change in real GDP year on year. Trend growth = the long-run sustainable rate at which the economy can grow without rising inflation, set by the supply-side fundamentals.', 1, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'List the four phases of the business cycle.', 'Recovery, boom (peak), slowdown, recession (trough). A recession is technically two consecutive quarters of negative real GDP growth.', 2, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'List four potential benefits of economic growth.', 'Higher living standards, higher tax revenue, lower unemployment, easier to redistribute, more government spending on public services, fiscal dividend, business confidence.', 3, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Give three costs of rapid economic growth.', 'Demand-pull inflation, current-account deficit (rising imports), environmental damage, widening inequality, resource depletion, working-time pressure on welfare.', 4, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Distinguish demand-pull and cost-push inflation.', 'Demand-pull: AD rises faster than AS — ''too much money chasing too few goods''. Cost-push: rising costs (wages, oil, taxes, weaker pound) shift SRAS leftward, raising P and lowering Y (stagflation possible).', 5, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Give the Fisher equation of exchange.', 'MV = PT. Money supply × velocity of circulation = price level × volume of transactions. Monetarists assume V and T are stable, so changes in M cause proportional changes in P.', 6, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'List four costs of high inflation.', 'Erodes purchasing power; menu costs; shoe-leather costs; uncertainty deters investment; loss of international competitiveness; income redistribution from creditors to debtors; ''fiscal drag''.', 7, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Why is deflation a problem?', 'Consumers delay purchases waiting for lower prices, depressing AD. Real value of debt rises, increasing default risk and bank stress (debt-deflation, Fisher 1933). Hard for central banks to escape with rates at zero.', 8, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'List four causes of unemployment.', 'Cyclical (demand-deficient), structural (mismatched skills/regions), frictional (between jobs), seasonal, real-wage (wages above clearing), classical/voluntary.', 9, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Give four costs of unemployment.', 'Lost output (operating inside PPF), lower tax revenue, higher benefits, hysteresis (long-term unemployed lose skills), social problems (mental health, crime), inequality.', 10, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'What does the short-run Phillips curve show?', 'A short-run inverse relationship between inflation and unemployment — lower unemployment requires higher inflation. Empirically observed in the 1960s; broke down in the 1970s under stagflation. <svg viewBox="0 0 220 150" width="220" height="150" style="display:block;margin:6px auto"><line x1="30" y1="130" x2="205" y2="130" stroke="#0B1E3F"/><line x1="30" y1="130" x2="30" y2="20" stroke="#0B1E3F"/><path d="M40 35 Q90 60 130 95 T200 125" stroke="#0B1E3F" stroke-width="1.5" fill="none"/><text x="200" y="35" font-size="9" fill="#0B1E3F" text-anchor="end">SRPC</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">π</text><text x="205" y="145" font-size="9" fill="#0B1E3F" text-anchor="end">U</text></svg>', 11, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'What does the long-run Phillips curve look like and why?', 'Vertical at the Natural Rate of Unemployment (NAIRU). Friedman: any attempt to push unemployment below NAIRU only raises inflation as workers update expectations. <svg viewBox="0 0 220 150" width="220" height="150" style="display:block;margin:6px auto"><line x1="30" y1="130" x2="205" y2="130" stroke="#0B1E3F"/><line x1="30" y1="130" x2="30" y2="20" stroke="#0B1E3F"/><line x1="120" y1="130" x2="120" y2="25" stroke="#0B1E3F" stroke-width="1.5"/><path d="M40 50 Q70 65 100 90 T160 130" stroke="#0B1E3F" stroke-width="1" fill="none" stroke-dasharray="3 2"/><path d="M70 35 Q100 50 130 75 T190 125" stroke="#0B1E3F" stroke-width="1" fill="none" stroke-dasharray="3 2"/><text x="123" y="22" font-size="9" fill="#0B1E3F">LRPC</text><text x="170" y="125" font-size="8" fill="#0B1E3F">SRPC</text><text x="120" y="145" font-size="9" fill="#0B1E3F" text-anchor="middle">NAIRU</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">π</text><text x="205" y="145" font-size="9" fill="#0B1E3F" text-anchor="end">U</text></svg>', 12, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'List two causes of a current-account deficit.', 'Strong domestic demand (sucking in imports), overvalued exchange rate, low productivity/competitiveness, deindustrialisation, slow growth in trading partners, high domestic inflation.', 13, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Why might a current-account deficit not be a problem?', 'It can reflect productive investment financed by capital inflows; reserve-currency status (US dollar) means the deficit can be funded easily; consumers benefit from cheap imports.', 14, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'How does the Marshall-Lerner condition relate to a depreciation?', 'A depreciation improves the current-account balance only if |PEDx| + |PEDm| > 1. Short-run elasticities are low (J-curve), so the deficit may worsen before improving. <svg viewBox="0 0 220 150" width="220" height="150" style="display:block;margin:6px auto"><line x1="30" y1="80" x2="205" y2="80" stroke="#0B1E3F"/><line x1="30" y1="130" x2="30" y2="20" stroke="#0B1E3F"/><path d="M30 80 Q70 130 110 95 T200 25" stroke="#0B1E3F" stroke-width="1.5" fill="none"/><line x1="50" y1="78" x2="50" y2="82" stroke="#0B1E3F"/><text x="50" y="95" font-size="8" fill="#0B1E3F" text-anchor="middle">depreciation</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">CA balance</text><text x="205" y="78" font-size="9" fill="#0B1E3F" text-anchor="end">time</text></svg>', 15, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'What is hysteresis in the labour market?', 'The persistence of unemployment after the original shock has passed, because the long-term unemployed lose skills, motivation and employability — raising the natural rate.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'List three roles of financial markets.', 'Channel funds from savers to borrowers, allocate capital efficiently, provide liquidity, price assets and risk, allow firms and governments to raise capital.', 1, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'Distinguish the money market from the capital market.', 'Money market: short-term debt instruments (under one year — Treasury bills, certificates of deposit, commercial paper). Capital market: long-term funds (shares and bonds with maturities of >1 year).', 2, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'What is the inverse relationship between bond prices and yields?', 'A bond pays a fixed coupon. If its market price falls, the coupon represents a higher % of the price — yield rises. Conversely, when bond demand rises, prices rise and yields fall.', 3, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'List three functions of commercial banks.', 'Accept deposits, make loans, provide payment services. Also offer foreign exchange, financial advice and credit/debit cards. Profit comes from the spread between deposit and loan interest rates.', 4, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'How do banks create credit?', 'When a bank makes a loan, it credits the borrower''s deposit account, expanding the money supply. Constrained by required reserves, capital ratios and demand for loans.', 5, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'List the four functions of a central bank.', 'Sole issuer of notes, banker to government, banker to commercial banks, lender of last resort. Conducts monetary policy and oversees financial stability (Prudential Regulation Authority in UK).', 6, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'Define moral hazard in banking.', 'When the protection offered by deposit insurance, bailouts or ''too big to fail'' status encourages banks to take excessive risk because they bear less of the downside.', 7, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'Outline the 2007-09 financial crisis in three sentences.', 'US sub-prime mortgages were bundled into mortgage-backed securities and sold globally. Defaults rose, exposing leveraged banks to huge losses; interbank lending froze. Major banks failed (Lehman) or were bailed out, triggering a global recession.', 8, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'What is monetary policy?', 'The use of interest rates and the money supply to influence AD and meet the inflation target. In the UK, set by the Bank of England''s nine-member Monetary Policy Committee, targeting 2% CPI.', 9, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'Through what four channels does Bank Rate transmit to inflation?', 'Market interest rates (mortgages, savings), asset prices (housing, shares), confidence/expectations, exchange rate. Each affects C, I, X-M and ultimately AD and inflation, with lags of 12-24 months.', 10, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'What is quantitative easing (QE)?', 'A central bank creates new money electronically to buy government bonds (and other assets), pushing up bond prices, lowering long-term yields, raising asset prices and bank reserves to stimulate AD when Bank Rate is near zero.', 11, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'Give two limitations of monetary policy.', 'Liquidity trap (rates near zero cannot fall further); time lags; uncertain transmission via banks; if banks won''t lend or households deleverage, low rates have little effect; widens inequality (asset-price boom).', 12, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'Distinguish micro- and macro-prudential regulation.', 'Microprudential focuses on stability of individual banks (capital, liquidity ratios). Macroprudential targets the financial system as a whole, e.g. counter-cyclical capital buffers, loan-to-income limits — overseen by the FPC in the UK.', 13, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'What is the difference between liquidity and solvency?', 'Liquidity: ability to meet short-run cash demands without distressed sale. Solvency: assets exceed liabilities. A bank can be solvent but illiquid (Northern Rock 2007).', 14, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'What are the Basel III capital requirements aimed at?', 'Strengthening bank resilience by raising minimum core capital ratios, introducing leverage and liquidity coverage ratios, and adding counter-cyclical buffers.', 15, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets and Monetary Policy', 'Define the term structure (yield curve) of interest rates.', 'The relationship between yields on bonds of equal credit quality but different maturities. Normally upward-sloping; an inverted curve (long < short) often precedes a recession.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'Define fiscal policy.', 'The use of government spending (G) and taxation (T) to influence AD, redistribute income and provide public goods. Set by the Treasury in the annual Budget.', 1, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'Distinguish direct and indirect taxes.', 'Direct: levied on income/wealth (income tax, NI, corporation tax) — paid by the person on whom it''s charged. Indirect: levied on spending (VAT, excise duties, fuel duty) — incidence can shift between buyer and seller.', 2, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'Define progressive, proportional and regressive taxes.', 'Progressive: average tax rate rises with income (UK income tax). Proportional: flat % of income. Regressive: average rate falls as income rises (VAT, council tax).', 3, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'List the four canons of taxation (Adam Smith).', 'Equity (ability to pay), certainty (clear amount/timing), convenience (easy to pay), economy (low collection cost). Modern additions: efficiency, flexibility, transparency.', 4, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'What is the difference between a budget deficit and the national debt?', 'A budget deficit is the gap between G and T in a single year (a flow). The national debt is the cumulative total of past borrowing (a stock). The deficit adds to the debt.', 5, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'Distinguish cyclical and structural budget deficits.', 'Cyclical: arises automatically when output is below trend (lower tax, higher benefits). Structural: persists at full employment, signalling that fiscal policy is fundamentally unsustainable.', 6, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'Define automatic stabilisers.', 'Features of the tax/benefits system that dampen the cycle without explicit policy change: tax revenues fall and benefits rise in a recession; both reverse in a boom.', 7, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'Describe expansionary fiscal policy and a likely effect on AD.', 'Cuts in taxes or rises in G shift AD right via the multiplier, raising output and employment in the short run, especially in a recession with spare capacity.', 8, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'What is crowding out?', 'When higher government borrowing pushes up interest rates and absorbs available savings, reducing private investment and consumption. Most relevant near full employment.', 9, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'List four UK fiscal rules used in recent years.', 'Cyclically-adjusted current balance over the cycle, debt/GDP falling by year five, welfare cap, and balanced current budget by a forecast date. Specific names change with government.', 10, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'Define supply-side policies.', 'Policies designed to raise the productive capacity (LRAS) and improve the long-run growth rate by improving the quantity or quality of factors of production and the efficiency of markets.', 11, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'Distinguish market-based and interventionist supply-side policies.', 'Market-based: free up markets — cut income/corporation tax, deregulation, privatisation, lower trade-union power. Interventionist: government action — infrastructure, education, R&D subsidies, training schemes.', 12, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'Give three benefits and two costs of supply-side policies.', 'Benefits: higher non-inflationary growth, lower structural unemployment, better trade balance. Costs: long time lags, regressive income effects of tax cuts, potential to worsen inequality, fiscal cost.', 13, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'What is the Laffer curve?', 'A graph showing tax revenue against tax rate. Revenue rises then falls as the rate rises beyond an optimum, because high rates discourage work, encourage avoidance and shrink the tax base. <svg viewBox="0 0 220 150" width="220" height="150" style="display:block;margin:6px auto"><line x1="30" y1="130" x2="205" y2="130" stroke="#0B1E3F"/><line x1="30" y1="130" x2="30" y2="20" stroke="#0B1E3F"/><path d="M30 130 Q115 0 200 130" stroke="#0B1E3F" stroke-width="1.5" fill="none"/><line x1="115" y1="130" x2="115" y2="60" stroke="#0B1E3F" stroke-width="0.5" stroke-dasharray="2 2"/><circle cx="115" cy="60" r="2.5" fill="#0B1E3F"/><text x="115" y="55" font-size="8" fill="#0B1E3F" text-anchor="middle">t*</text><text x="28" y="18" font-size="9" fill="#0B1E3F" text-anchor="end">Revenue</text><text x="205" y="145" font-size="9" fill="#0B1E3F" text-anchor="end">Tax rate</text></svg>', 14, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'Why might monetary and fiscal policy need to be coordinated?', 'They influence AD jointly. A loose fiscal stance combined with tight monetary policy creates conflicting signals, raising long-term rates and worsening the policy mix; coordination improves outcomes.', 15, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal and Supply-Side Policies', 'Explain the Office for Budget Responsibility (OBR).', 'An independent UK body created in 2010 that produces official forecasts of growth, inflation and the public finances, and judges whether the government is meeting its fiscal rules.', 16, 'alevel');
